and t.asset_name like concat('%', #{assetName}, '%')
and t.asset_no like concat('%', #{assetNo}, '%')
and t.asset_type = #{assetType}
and t.asset_sub_type in
#{item}
and t.amount >= #{amount}
and t.asset_status in
#{item}
order by t.update_time desc

